<?php
namespace App\Domain\Inventory\Capacity;
use App\Domain\Hunts\Rewards\HuntRewardStatus;
use App\Domain\Inventory\Capacity\Data\InventoryCapacityResult;
use App\Models\Character;
use App\Models\CharacterItem;
use App\Models\HuntReward;
use App\Models\HuntRewardItem;
use App\Models\Item;
use Carbon\CarbonImmutable;
use Illuminate\Support\Facades\DB;
use InvalidArgumentException;
final class PendingRewardCapacityService{private $slots;private $capacity;public function __construct(InventorySlotCalculator $slots,InventoryCapacityCalculator $capacity){$this->slots=$slots;$this->capacity=$capacity;}public function snapshot(Character $character,CarbonImmutable $now=null){return$this->calculate($character,$now?:CarbonImmutable::now(),false);}public function locked(Character $character,CarbonImmutable $now){if(DB::transactionLevel()<1)throw new \RuntimeException('Active transaction required.');return$this->calculate($character,$now,true);}public function fromLoadedState(Character $character,$inventory,$rewardItems,$items,CarbonImmutable $now){list($effective,$permanent,$temporary)=$this->capacity->effective($character,$now);$allIds=$inventory->pluck('item_id')->merge($rewardItems->pluck('item_id'))->unique();$missing=$allIds->filter(function($id)use($items){return!$items->has($id);})->values();if($missing->isNotEmpty()){$loaded=Item::whereIn('id',$missing)->get()->keyBy('id');$items=$items->union($loaded);} $current=[];$projected=[];foreach($inventory as $entry){$line=$this->line($entry->item_id,$entry->quantity,$items);$current[]=$line;$projected[]=$line;}foreach($rewardItems as $entry)$projected[]=$this->line($entry->item_id,$entry->quantity,$items);return$this->capacity->result($effective,$permanent,$temporary,$this->slots->calculate($current)->slots(),$this->slots->calculate($projected)->slots());}private function calculate(Character $character,CarbonImmutable $now,$lock){$inventoryQuery=CharacterItem::where('character_id',$character->id)->orderBy('id');if($lock)$inventoryQuery->lockForUpdate();$inventory=$inventoryQuery->get();$rewardQuery=HuntReward::query()->select('hunt_rewards.*')->join('hunting_sessions','hunting_sessions.id','=','hunt_rewards.hunting_session_id')->where('hunting_sessions.character_id',$character->id)->where('hunt_rewards.status',HuntRewardStatus::PENDING)->orderBy('hunt_rewards.id');if($lock)$rewardQuery->lockForUpdate();$rewards=$rewardQuery->get();$rewardIds=$rewards->pluck('id');$rewardItems=collect();if($rewardIds->isNotEmpty()){$query=HuntRewardItem::whereIn('hunt_reward_id',$rewardIds)->orderBy('id');if($lock)$query->lockForUpdate();$rewardItems=$query->get();}$itemIds=$inventory->pluck('item_id')->merge($rewardItems->pluck('item_id'))->unique()->values();$items=Item::whereIn('id',$itemIds)->get()->keyBy('id');return$this->fromLoadedState($character,$inventory,$rewardItems,$items,$now);}private function line($itemId,$quantity,$items){$item=$items->get($itemId);if(!$item||$item->max_stack===null)throw new InvalidArgumentException('Item requires a valid max stack.');$quantity=$this->safeInteger($quantity);$max=$this->safeInteger($item->max_stack);return['item_id'=>(int)$itemId,'quantity'=>$quantity,'max_stack'=>$max];}private function safeInteger($value){if(is_int($value))return$value;if(!is_string($value)||!preg_match('/^(0|[1-9][0-9]*)$/',$value)||strlen($value)>strlen((string)PHP_INT_MAX)||(strlen($value)===strlen((string)PHP_INT_MAX)&&strcmp($value,(string)PHP_INT_MAX)>0))throw new InvalidArgumentException('Quantity exceeds safe PHP integer range.');return(int)$value;}}
